## Testing with MockLLM

Use `MockLLM` for deterministic testing without API calls. Mock responses are returned sequentially from the `outputs` list:

```jac
import from jaclang.byllm.lib { MockLLM }

glob llm = MockLLM(
    model_name="mockllm",
    config={
        "outputs": ["Mocked response 1", "Mocked response 2"]
    }
);

def translate(text: str) -> str by llm();
def summarize(text: str) -> str by llm();

test "translate returns first mock" {
    result = translate("Hello");
    assert result == "Mocked response 1";
}

test "summarize returns second mock" {
    result = summarize("Long text...");
    assert result == "Mocked response 2";
}
```

`MockLLM` is useful for:

- Unit testing LLM-powered functions without API costs
- Deterministic assertions on function behavior
- CI/CD pipelines where API keys aren't available

#### Injecting usage metadata (for compaction tests)

Each entry in `outputs` may be a `(payload, usage_dict)` tuple to inject token-usage metadata. This lets you test threshold-based auto-compaction without a real model:

```jac
import from jaclang.byllm.lib { MockLLM, MockToolCall }

def step_a -> str { return "a"; }
def finish_tool(final_output: str) -> str { return final_output; }

glob llm = MockLLM(
    model_name="mockllm",
    ctx_window=1000,
    config={"outputs": [
        # (tool_call, usage) - triggers compaction at 85 % of 1000 tokens
        (MockToolCall(tool=step_a, args={}), {"prompt_tokens": 850, "total_tokens": 950}),
        # plain entry - no usage injection, loop exits via finish_tool
        MockToolCall(tool=finish_tool, args={"final_output": "done"})
    ]}
);
```

Non-tuple entries behave exactly as before - usage defaults to `{

```jac
impl Board.attacked_squares(by_color: Color) -> set[tuple[int, int]] {
    attacked: set[tuple[int, int]] = set();
    for piece in self.pieces_of(by_color) {
        attacked |= {m.to_pos for m in piece.raw_moves(self)};
    }
    return attacked;
}
```

### Bitwise Operations for Castling

Castling rights use bitwise flags -- AND, OR, NOT:

<!-- jac-skip -->
```jac
# King moved -- remove both castling rights for that side
if piece.kind == PieceKind.KING {
    if piece.color == Color.WHITE {
        self.castling_rights &= ~(CASTLE_WK | CASTLE_WQ);
    } else {
        self.castling_rights &= ~(CASTLE_BK | CASTLE_BQ);
    }
}
```

### Position Evaluation

The evaluator uses material values, center-control bonuses, and development bonuses:

```jac
impl Board.evaluate(color: Color) -> int {
    score = 0;
    for r in range(BOARD_SIZE) {
        for c in range(BOARD_SIZE) {
            piece: Piece | None = self.squares[r][c];
            if piece is not None {
                base = PIECE_VALUES[piece.kind];
                center_bonus = 0;
                if (1 << c & CENTER_MASK) != 0 and 2 <= r and r <= 5 {
                    center_bonus = base // 10;
                }
                dev_bonus = 8 if piece.has_moved and piece.kind != PieceKind.KING else 0;
                total = base + center_bonus + dev_bonus;
                if piece.color == color {
                    score += total;
                } else {
                    score -= total;
                }
            }
        }
    }
    return score;
}
```

### Benchmark Mode

The `benchmark` method runs N automated games and reports results:

```jac
impl Game.benchmark(num_games: int) -> None {
    white_wins = 0;
    black_wins = 0;
    draws = 0;

    print(f"Running {num_games} games...\n");

    for i in range(num_games) {
        g = Game();
        seed_random(i * 7919 + 42);
        result = g.play_auto();

        if result == "White" { white_wins += 1; }
        elif result == "Black" { black_wins += 1; }
        else { draws += 1; }

        print(f"Game {i + 1}: {result} wins" if result != "Draw" else f"Game {i + 1}: Draw");
    }

    print(f"\n--- Results ({num_games} games) ---");
    print(f"White wins: {white_wins}");
    print(f"Black wins: {black_wins}");
    print(f"Draws:      {draws}");
}
```

