credentials    [{type, password_hash}, ...]
root_id        hex ID of the user's Jac graph root node
profile        {firstname?, lastname?, ..., sso?: {<platform>: {...}}}
created_at     ISO 8601 timestamp
updated_at     ISO 8601 timestamp
